'use server'

import OpenAI from 'openai'
import { getPgPool } from '@/lib/db/pool'

export type Message = {
  id: string
  role: 'user' | 'assistant'
  content: string
  timestamp: string
}

const SYSTEM_PROMPT = `Você é a "Inteligência Cívica" do portal Meus Políticos.
Seu objetivo é explicar projetos de lei de forma extremamente simples, neutra e didática para cidadãos leigos, sem jargões jurídicos ("sem juridiquês").
REGRAS:
1. Mantenha um tom apartidário, neutro, puramente informativo.
2. Não tome partido se o projeto é bom ou ruim; explique os impactos práticos (ex: se aumenta imposto, se cria benefício, quem é afetado).
3. Responda de forma concisa e em parágrafos curtos.
4. Se o usuário fizer perguntas fora do escopo do projeto de lei fornecido, explique polidamente que seu foco é tirar dúvidas sobre esta matéria legislativa específica.`

export async function perguntarIA(
  projetoId: string,
  historico: Message[],
  pergunta: string
): Promise<{ resposta: string } | { erro: string }> {
  if (!pergunta || pergunta.trim().length === 0) {
    return { erro: 'A pergunta não pode estar vazia.' }
  }

  try {
    const db = getPgPool()

    // Busca informações detalhadas do projeto no banco de dados para alimentar o contexto do prompt
    const { rows } = await db.query(
      `SELECT tipo, numero, ano, ementa, ementa_simples, titulo_simplificado, situacao 
       FROM proposicoes 
       WHERE id = $1 LIMIT 1`,
      [projetoId]
    )

    const projeto = rows[0]
    if (!projeto) {
      return { erro: 'Projeto de lei não encontrado.' }
    }

    const context = `INFORMAÇÕES DO PROJETO DE LEI:
Tipo: ${projeto.tipo}
Número: ${projeto.numero}/${projeto.ano}
Título/Tema: ${projeto.titulo_simplificado ?? 'Não disponível'}
Ementa Oficial: ${projeto.ementa ?? 'Não disponível'}
Resumo Cidadão (IA): ${projeto.ementa_simples ?? 'Não disponível'}
Situação atual: ${projeto.situacao ?? 'Em tramitação'}`

    const apiKey = process.env.OPENAI_API_KEY
    if (!apiKey) {
      // Fallback inteligente caso a chave OpenAI não esteja configurada
      return {
        resposta: obterRespostaLocal(projeto, pergunta),
      }
    }

    const client = new OpenAI({ apiKey })
    const messagesChat: OpenAI.Chat.ChatCompletionMessageParam[] = [
      { role: 'system', content: SYSTEM_PROMPT },
      { role: 'system', content: `CONTEXTO DO PROJETO LEGISLATIVO:\n${context}` },
      ...historico.map((m) => ({
        role: m.role,
        content: m.content,
      })),
      { role: 'user', content: pergunta },
    ]

    const response = await client.chat.completions.create({
      model: 'gpt-4o-mini',
      temperature: 0.3,
      max_tokens: 400,
      messages: messagesChat,
    })

    const reply = response.choices[0]?.message?.content ?? ''
    if (!reply) {
      return { erro: 'Não foi possível gerar uma resposta. Tente novamente mais tarde.' }
    }

    return { resposta: reply }
  } catch (error: any) {
    console.error('[IA Pergunta Projeto Error]:', error)
    return { erro: 'Erro ao processar a pergunta da Inteligência Cívica.' }
  }
}

// Resposta determinística local baseada no projeto se a chave da API estiver indisponível
function obterRespostaLocal(projeto: any, pergunta: string): string {
  const query = pergunta.toLowerCase()
  const nomePL = `${projeto.tipo} ${projeto.numero}/${projeto.ano}`
  const tema = projeto.titulo_simplificado || 'esta matéria legislativa'

  if (query.includes('afeta') || query.includes('bolso') || query.includes('dinheiro') || query.includes('custar') || query.includes('custo')) {
    return `Sobre os impactos financeiros do **${nomePL}** (${tema}):
A ementa oficial aponta que o projeto trata de: *"${projeto.ementa || 'Sem descrição oficial'}"*. 

De forma prática, o projeto define regras regulatórias ou organizacionais. Para saber o impacto financeiro exato na sua região, é importante acompanhar as estimativas de impacto orçamentário que são anexadas durante a análise pelas comissões de Finanças e Tributação da respectiva Casa.`
  }

  if (query.includes('situacao') || query.includes('status') || query.includes('onde esta') || query.includes('tramitando')) {
    return `O **${nomePL}** está atualmente com o status: **"${projeto.situacao || 'Em tramitação'}"**. 
Isso significa que a matéria está seguindo os ritos das comissões técnicas oficiais ou aguarda votação em plenário. Você pode acompanhar a linha do tempo completa de andamento na seção de "Tramitação" nesta mesma página.`
  }

  if (query.includes('resumo') || query.includes('o que e') || query.includes('funciona') || query.includes('explica')) {
    return `Aqui está uma explicação simples sobre o **${nomePL}** (${tema}):
Este projeto visa regulamentar ou alterar normas vigentes sobre o assunto principal descrito na ementa.
- **O que propõe:** *"${projeto.ementa_simples || projeto.ementa || 'Proposta em tramitação legislativa'}"*.
- **Quem afeta:** Cidadãos e instituições relacionadas à área do tema regulado.
- **Situação:** Atualmente está classificado como *"${projeto.situacao || 'Em tramitação'}"*.`
  }

  return `Entendi sua dúvida sobre o **${nomePL}** (${tema}). 
Como a chave de acesso direto à API de Inteligência Artificial não está ativada no ambiente de testes local, aqui está o resumo do que dispomos oficialmente:
- **Assunto:** ${projeto.ementa || 'Não há detalhes adicionais cadastrados.'}
- **Situação da matéria:** ${projeto.situacao || 'Em tramitação'}

Se precisar de detalhes técnicos específicos ou pareceres de relatores, consulte os links na seção "Documentos Oficiais".`
}

export async function perguntarPoliticoIA(
  politicoId: string,
  historico: Message[],
  pergunta: string
): Promise<{ resposta: string } | { erro: string }> {
  if (!pergunta || pergunta.trim().length === 0) {
    return { erro: 'A pergunta não pode estar vazia.' }
  }

  try {
    const db = getPgPool()
    const { rows } = await db.query(
      `SELECT p.nome, p.nome_eleitoral, p.cargo::text AS cargo, p.uf,
              p.presenca_pct_atual, p.gasto_total_ano, p.total_votacoes,
              pt.sigla AS partido_sigla
       FROM politicos p
       LEFT JOIN partidos pt ON pt.id = p.partido_id
       WHERE p.id = $1 LIMIT 1`,
      [politicoId]
    )

    const politico = rows[0]
    if (!politico) {
      return { erro: 'Político não encontrado.' }
    }

    const nome = politico.nome_eleitoral || politico.nome
    const cargo = politico.cargo === 'senador' ? 'Senador(a)' : 'Deputado(a) Federal'
    const context = `INFORMAÇÕES DE ATUAÇÃO PARLAMENTAR:
Nome: ${nome}
Cargo: ${cargo}
Partido/UF: ${politico.partido_sigla ?? 'Sem partido'} · ${politico.uf ?? '–'}
Taxa de Presença: ${politico.presenca_pct_atual != null ? `${Math.round(politico.presenca_pct_atual)}%` : 'Não informada'}
Gasto total acumulado no ano (CEAP): ${politico.gasto_total_ano != null ? `R$ ${Number(politico.gasto_total_ano).toLocaleString('pt-BR')}` : 'Não informado'}
Total de Votações Nominais registradas: ${politico.total_votacoes ?? 0}`

    const apiKey = process.env.OPENAI_API_KEY
    if (!apiKey) {
      return {
        resposta: obterRespostaPoliticoLocal(politico, pergunta),
      }
    }

    const client = new OpenAI({ apiKey })
    const systemPromptPolitico = `Você é a "Inteligência Cívica" do portal Meus Políticos.
Seu objetivo é explicar a atuação parlamentar, gastos e dados oficiais de presença de ${nome} em linguagem cidadã direta e simples.
REGRAS:
1. Mantenha um tom 100% neutro, sem juízo de valor.
2. Explique os números no contexto (ex: o teto máximo de gastos, se a presença é alta ou baixa, o que os gastos significam).
3. Seja breve e responda em parágrafos curtos.`

    const response = await client.chat.completions.create({
      model: 'gpt-4o-mini',
      temperature: 0.3,
      max_tokens: 400,
      messages: [
        { role: 'system', content: systemPromptPolitico },
        { role: 'system', content: `CONTEXTO DO PARLAMENTAR:\n${context}` },
        ...historico.map((m) => ({
          role: m.role,
          content: m.content,
        })),
        { role: 'user', content: pergunta },
      ],
    })

    const reply = response.choices[0]?.message?.content ?? ''
    if (!reply) {
      return { erro: 'Não foi possível gerar uma resposta. Tente novamente.' }
    }

    return { resposta: reply }
  } catch (error) {
    console.error('[IA Pergunta Politico Error]:', error)
    return { erro: 'Erro ao processar a pergunta sobre o político.' }
  }
}

function obterRespostaPoliticoLocal(politico: any, pergunta: string): string {
  const query = pergunta.toLowerCase()
  const nome = politico.nome_eleitoral || politico.nome
  const cargo = politico.cargo === 'senador' ? 'Senador(a)' : 'Deputado(a) Federal'

  if (query.includes('gasto') || query.includes('ceap') || query.includes('dinheiro') || query.includes('despesa')) {
    return `Sobre as despesas de gabinete de **${nome}**:
O parlamentar registrou um gasto total acumulado de **R$ ${
      politico.gasto_total_ano != null ? Number(politico.gasto_total_ano).toLocaleString('pt-BR') : '–'
    }** neste ano. 

Esses recursos pertencem à Cota para Exercício da Atividade Parlamentar (CEAP), usada para ressarcir despesas como passagens aéreas, combustível e manutenção de escritório político. Você pode ver o detalhamento por categoria na aba de "Gastos".`
  }

  if (query.includes('presenca') || query.includes('falta') || query.includes('sessao') || query.includes('plenario')) {
    return `Sobre a presença legislativa de **${nome}**:
O parlamentar possui uma taxa de presença de **${
      politico.presenca_pct_atual != null ? `${Math.round(politico.presenca_pct_atual)}%` : '–'
    }** nas sessões plenárias oficiais registradas. 

Isso reflete o comparecimento do parlamentar nas convocações de votação do plenário da Câmara ou Senado. As justificativas de faltas são registradas pelas respectivas comissões de corregedoria e mesa diretora.`
  }

  return `Aqui está um resumo da atuação de **${nome}** (${cargo} · ${politico.partido_sigla ?? 'Sem partido'}/${politico.uf ?? '–'}):
- **Presença em Sessões:** ${politico.presenca_pct_atual != null ? `${Math.round(politico.presenca_pct_atual)}%` : 'Dados indisponíveis'}
- **Gastos Totais Declarados:** ${politico.gasto_total_ano != null ? `R$ ${Number(politico.gasto_total_ano).toLocaleString('pt-BR')}` : 'Dados indisponíveis'}
- **Votações Registradas:** ${politico.total_votacoes ?? 0} votações nominais.

Para dúvidas mais específicas ou para ver como ele votou em projetos individuais, navegue pelas abas "Votações" e "Gastos" deste perfil.`
}

export async function perguntarEmendaIA(
  emendaId: string,
  historico: Message[],
  pergunta: string
): Promise<{ resposta: string } | { erro: string }> {
  if (!pergunta || pergunta.trim().length === 0) {
    return { erro: 'A pergunta não pode estar vazia.' }
  }

  try {
    const db = getPgPool()

    // Busca informações detalhadas da emenda no banco de dados para alimentar o contexto do prompt
    const { rows } = await db.query(
      `SELECT e.numero_emenda AS codigo_emenda, e.ano, e.valor, e.valor_pago,
              e.municipio_nome, e.uf_municipio, e.funcao, e.area, e.tipo_emenda,
              p.nome_eleitoral AS autor_nome, pt.sigla AS partido_sigla
       FROM emendas e
       LEFT JOIN politicos p ON p.id = e.politico_id
       LEFT JOIN partidos pt ON pt.id = p.partido_id
       WHERE e.id = $1 LIMIT 1`,
      [emendaId]
    )

    const emenda = rows[0]
    if (!emenda) {
      return { erro: 'Emenda não encontrada.' }
    }

    const context = `INFORMAÇÕES DA EMENDA PARLAMENTAR:
Código: ${emenda.codigo_emenda}
Ano: ${emenda.ano}
Tipo: ${emenda.tipo_emenda ?? 'Não especificado'}
Autor: ${emenda.autor_nome ?? 'Bancada / Coletivo'} (${emenda.partido_sigla ?? 'Sem partido'})
Valor Empenhado (Reservado): R$ ${Number(emenda.valor || 0).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
Valor Pago: R$ ${Number(emenda.valor_pago || 0).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
Cidade de Destino: ${emenda.municipio_nome ?? 'Não especificada'} - ${emenda.uf_municipio ?? '–'}
Função/Área: ${emenda.funcao ?? 'Não especificada'} / ${emenda.area ?? 'Não especificada'}`

    const apiKey = process.env.OPENAI_API_KEY
    if (!apiKey) {
      return {
        resposta: obterRespostaEmendaLocal(emenda, pergunta),
      }
    }

    const client = new OpenAI({ apiKey })
    const systemPromptEmenda = `Você é a "Inteligência Cívica" do portal Meus Políticos.
Seu objetivo é explicar como emendas parlamentares funcionam, como o orçamento público é executado e o que significa a destinação para esta emenda de forma simples e didática.
REGRAS:
1. Mantenha um tom apartidário, neutro, puramente informativo.
2. Explique os jargões orçamentários (ex: "Empenhado", "Pago", "Transferência Especial/Pix", "Finalidade Definida") em linguagem simples.
3. Não emita juízo de valor sobre o político ou sobre a destinação ser boa ou má; descreva apenas fatos e como funciona a fiscalização.
4. Responda de forma concisa e em parágrafos curtos.`

    const response = await client.chat.completions.create({
      model: 'gpt-4o-mini',
      temperature: 0.3,
      max_tokens: 400,
      messages: [
        { role: 'system', content: systemPromptEmenda },
        { role: 'system', content: `CONTEXTO DA EMENDA:\n${context}` },
        ...historico.map((m) => ({
          role: m.role,
          content: m.content,
        })),
        { role: 'user', content: pergunta },
      ],
    })

    const reply = response.choices[0]?.message?.content ?? ''
    if (!reply) {
      return { erro: 'Não foi possível gerar uma resposta. Tente novamente mais tarde.' }
    }

    return { resposta: reply }
  } catch (error: any) {
    console.error('[IA Pergunta Emenda Error]:', error)
    return { erro: 'Erro ao processar a pergunta sobre a emenda.' }
  }
}

function obterRespostaEmendaLocal(emenda: any, pergunta: string): string {
  const query = pergunta.toLowerCase()
  const cod = emenda.codigo_emenda
  const cidade = emenda.municipio_nome || 'município'
  const autor = emenda.autor_nome || 'autor'
  const val = Number(emenda.valor_pago || emenda.valor || 0).toLocaleString('pt-BR')

  if (query.includes('pix') || query.includes('especial')) {
    return `Esta emenda **${cod}** do tipo *"${emenda.tipo_emenda || 'especial'}"* é conhecida popularmente como "emenda pix" se for uma Transferência Especial. 
Nas emendas pix, o dinheiro é depositado diretamente no caixa geral da prefeitura de **${cidade}** sem necessidade de convênio prévio ou projeto técnico complexo. A prefeitura tem liberdade para gastar em custeio e investimentos, exceto no pagamento de salários de servidores e juros de dívidas.`
  }

  if (query.includes('como fiscalizar') || query.includes('onde ver') || query.includes('fiscalizar') || query.includes('auditar')) {
    return `Para fiscalizar a emenda **${cod}** destinada para **${cidade}**:
1. **No Município**: Acesse o Portal da Transparência da Prefeitura de ${cidade} ou procure o Diário Oficial local para ver em qual contrato, licitação ou obra o valor de **R$ ${val}** foi alocado.
2. **No Tribunal de Contas**: Você pode acessar o site do Tribunal de Contas do Estado (TCE) correspondente ou do TCU para checar processos relacionados ao município.
3. **Conselhos Municipais**: Cidadãos podem cobrar informações nos conselhos municipais de Saúde, Educação ou Assistência Social, dependendo da área da emenda.`
  }

  return `Esta emenda parlamentar **${cod}** foi enviada por **${autor}** para **${cidade}**, com o valor pago de **R$ ${val}** na área de **${emenda.funcao || emenda.area || 'Desenvolvimento'}**. 

De forma local, recursos pagos já estão disponíveis para uso da prefeitura conforme a destinação definida no plano orçamentário. Você pode consultar o portal oficial de contratos do município para acompanhar o início das obras ou compra de equipamentos.`
}

export async function perguntarGlossarioIA(
  termoSlug: string,
  historico: Message[],
  pergunta: string
): Promise<{ resposta: string } | { erro: string }> {
  if (!pergunta || pergunta.trim().length === 0) {
    return { erro: 'A pergunta não pode estar vazia.' }
  }

  try {
    const db = getPgPool()
    const { rows } = await db.query(
      `SELECT termo, definicao_simples, definicao_tecnica, exemplo, categoria 
       FROM glossario 
       WHERE slug = $1 LIMIT 1`,
      [termoSlug]
    )

    const verbete = rows[0]
    if (!verbete) {
      return { erro: 'Termo do glossário não encontrado.' }
    }

    const context = `INFORMAÇÕES DO TERMO POLÍTICO:
Termo: ${verbete.termo}
Categoria: ${verbete.categoria ?? 'Geral'}
Definição Simples: ${verbete.definicao_simples}
Definição Técnica: ${verbete.definicao_tecnica ?? 'Não disponível'}
Exemplo Prático: ${verbete.exemplo ?? 'Não disponível'}`

    const apiKey = process.env.OPENAI_API_KEY
    if (!apiKey) {
      return {
        resposta: obterRespostaGlossarioLocal(verbete, pergunta),
      }
    }

    const client = new OpenAI({ apiKey })
    const systemPromptGlossario = `Você é a "Inteligência Cívica" do portal Meus Políticos.
Seu objetivo é tirar dúvidas sobre o termo político "${verbete.termo}" de forma simples, didática e neutra para cidadãos leigos, sem "juridiquês".
REGRAS:
1. Mantenha um tom apartidário, neutro e informativo.
2. Explique em termos claros e dê exemplos cotidianos se necessário.
3. Responda de forma concisa e em parágrafos curtos.
4. Se a pergunta for totalmente fora do tema, explique polidamente que está focado em explicar o termo "${verbete.termo}".`

    const response = await client.chat.completions.create({
      model: 'gpt-4o-mini',
      temperature: 0.3,
      max_tokens: 400,
      messages: [
        { role: 'system', content: systemPromptGlossario },
        { role: 'system', content: `CONTEXTO DO VERBETE:\n${context}` },
        ...historico.map((m) => ({
          role: m.role,
          content: m.content,
        })),
        { role: 'user', content: pergunta },
      ],
    })

    const reply = response.choices[0]?.message?.content ?? ''
    if (!reply) {
      return { erro: 'Não foi possível gerar uma resposta. Tente novamente.' }
    }

    return { resposta: reply }
  } catch (error) {
    console.error('[IA Pergunta Glossario Error]:', error)
    return { erro: 'Erro ao processar a pergunta sobre o termo.' }
  }
}

function obterRespostaGlossarioLocal(verbete: any, pergunta: string): string {
  const query = pergunta.toLowerCase()
  const termo = verbete.termo

  if (query.includes('exemplo') || query.includes('prática') || query.includes('funciona')) {
    if (verbete.exemplo) {
      return `Aqui está um exemplo prático de como funciona o termo **${termo}**:\n\n*${verbete.exemplo}*`
    }
    return `O termo **${termo}** se aplica na prática do dia a dia legislativo e administrativo. Por exemplo, serve para estruturar processos públicos e decisões do orçamento ou votações.`
  }

  if (query.includes('porque importa') || query.includes('por que importa') || query.includes('importancia') || query.includes('técnico')) {
    if (verbete.definicao_tecnica) {
      return `Veja a importância técnica de **${termo}**:\n\n${verbete.definicao_tecnica}`
    }
  }

  return `Aqui está a explicação sobre **${termo}**:
- **O que significa:** ${verbete.definicao_simples}
${verbete.exemplo ? `- **Na prática:** *${verbete.exemplo}*` : ''}

Caso tenha dúvidas mais específicas, você pode consultar o regimento interno das Casas Legislativas ou a Constituição Federal.`
}

import { redirect } from 'next/navigation'
import { Pool } from 'pg'

import { AdminPageHeader, KpiCard, StatusBadge } from '@/components/admin/AdminCard'
import { getCurrentUser } from '@/lib/auth/current-user'

export const metadata = { title: 'Dashboard Admin — Meus Políticos' }

type EtlRow = {
  fonte: string
  status: string
  criado_em: string
  duracao_ms: number | null
  registros: number | null
  mensagem: string | null
}

type CountRow = {
  count: number | string
}

let _pool: Pool | null = null
function getPool(): Pool {
  if (!_pool) {
    _pool = new Pool({
      host: process.env.POSTGRES_HOST ?? 'localhost',
      port: Number(process.env.POSTGRES_PORT ?? 5432),
      database: process.env.POSTGRES_DB ?? 'meuspoliticos_db',
      user: process.env.POSTGRES_USER ?? 'postgres',
      password: process.env.POSTGRES_PASSWORD,
      max: 5,
      idleTimeoutMillis: 30_000,
    })
  }

  return _pool
}

function etlBadgeVariant(status: string): 'ok' | 'warn' | 'err' | 'never' {
  if (status === 'ok' || status === 'sucesso') return 'ok'
  if (status === 'parcial' || status === 'aviso') return 'warn'
  if (status === 'erro' || status === 'falha') return 'err'
  return 'never'
}

function fmtDuration(ms: number | null): string {
  if (!ms) return '—'
  if (ms < 1000) return `${ms}ms`
  return `${(ms / 1000).toFixed(1)}s`
}

function fmtDate(iso: string): string {
  const d = new Date(iso)
  return d.toLocaleString('pt-BR', {
    day: '2-digit',
    month: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
  })
}

function fmtNum(n: number | null): string {
  if (n === null || n === undefined) return '—'
  return n.toLocaleString('pt-BR')
}

async function countRows(pool: Pool, table: string): Promise<number> {
  const { rows } = await pool.query<CountRow>(`SELECT COUNT(*)::int AS count FROM ${table}`)
  return Number(rows[0]?.count ?? 0)
}

export default async function AdminDashboardPage() {
  const currentUser = await getCurrentUser()

  if (!currentUser) {
    redirect('/login')
  }

  if (currentUser.role !== 'admin') {
    redirect('/painel')
  }

  const pool = getPool()

  // User stats
  const totalUsers = await countRows(pool, 'perfis')

  const since7d = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString()
  const { rows: newUsersRows } = await pool.query<CountRow>(
    'SELECT COUNT(*)::int AS count FROM perfis WHERE criado_em >= $1',
    [since7d],
  )
  const newUsers7d = Number(newUsersRows[0]?.count ?? 0)

  const counts = await Promise.all([
    countRows(pool, 'politicos'),
    countRows(pool, 'emendas'),
    countRows(pool, 'gastos'),
    countRows(pool, 'votacoes'),
    countRows(pool, 'proposicoes'),
    countRows(pool, 'municipios'),
  ])

  const [politicos, emendas, gastos, votacoes, proposicoes, municipios] = counts

  // ETL latest per fonte
  const { rows: etlRaw } = await pool.query<EtlRow>(
    `SELECT fonte, status, criado_em::text AS criado_em, duracao_ms, registros, mensagem
     FROM coletas_log
     ORDER BY criado_em DESC
     LIMIT 200`
  )

  // Group by fonte — pick latest per fonte
  const etlMap = new Map<string, EtlRow>()
  for (const row of etlRaw ?? []) {
    if (!etlMap.has(row.fonte)) etlMap.set(row.fonte, row)
  }
  const etlLatest = Array.from(etlMap.values())

  // Alert if any ETL failed in last 24h
  const since24h = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString()
  const failedRecent = etlLatest.filter(
    (r) =>
      (r.status === 'erro' || r.status === 'falha') && r.criado_em > since24h
  )

  const dbCards = [
    { label: 'Políticos', value: politicos },
    { label: 'Emendas', value: emendas },
    { label: 'Gastos', value: gastos },
    { label: 'Votações', value: votacoes },
    { label: 'Proposições', value: proposicoes },
    { label: 'Municípios', value: municipios },
  ]

  return (
    <div style={{ padding: '32px 36px', maxWidth: 1100 }}>
      <AdminPageHeader
        title="Dashboard"
        subtitle="Visão geral do sistema — dados em tempo real"
      />

      {/* Alert banner */}
      {failedRecent.length > 0 && (
        <div
          style={{
            background: 'var(--neg-soft)',
            borderLeft: '3px solid var(--neg)',
            borderRadius: 8,
            padding: '12px 16px',
            marginBottom: 24,
            display: 'flex',
            alignItems: 'center',
            gap: 10,
          }}
        >
          <span style={{ fontSize: 18 }}>⚠</span>
          <span style={{ fontSize: 14, color: 'var(--neg)', fontWeight: 500 }}>
            {failedRecent.length} ETL{failedRecent.length > 1 ? 's falharam' : ' falhou'} nas
            últimas 24h:{' '}
            <strong>{failedRecent.map((r) => r.fonte).join(', ')}</strong>
          </span>
        </div>
      )}

      {/* Users KPIs */}
      <h2 style={{ fontSize: 13, fontWeight: 600, letterSpacing: '0.06em', color: 'var(--ink-3)', marginBottom: 12 }}>
        USUÁRIOS
      </h2>
      <div
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fill, minmax(160px, 1fr))',
          gap: 12,
          marginBottom: 28,
        }}
      >
        <KpiCard label="Total de usuários" value={fmtNum(totalUsers)} />
        <KpiCard label="Novos (7 dias)" value={fmtNum(newUsers7d)} />
      </div>

      {/* DB KPIs */}
      <h2 style={{ fontSize: 13, fontWeight: 600, letterSpacing: '0.06em', color: 'var(--ink-3)', marginBottom: 12 }}>
        BASE DE DADOS
      </h2>
      <div
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fill, minmax(140px, 1fr))',
          gap: 12,
          marginBottom: 32,
        }}
      >
        {dbCards.map((c) => (
          <KpiCard key={c.label} label={c.label} value={fmtNum(c.value)} />
        ))}
      </div>

      {/* ETL Status table */}
      <h2 style={{ fontSize: 13, fontWeight: 600, letterSpacing: '0.06em', color: 'var(--ink-3)', marginBottom: 12 }}>
        STATUS DOS ETLs
      </h2>

      {etlLatest.length === 0 ? (
        <div
          style={{
            background: 'var(--panel)',
            borderRadius: 10,
            boxShadow: '0 1px 4px rgba(0,0,0,0.06)',
            padding: '32px',
            textAlign: 'center',
            color: 'var(--ink-3)',
            fontSize: 14,
          }}
        >
          Nenhum registro em <code>coletas_log</code> ainda.
        </div>
      ) : (
        <div
          style={{
            background: 'var(--panel)',
            borderRadius: 10,
            boxShadow: '0 1px 4px rgba(0,0,0,0.06)',
            overflow: 'hidden',
          }}
        >
          <table
            style={{
              width: '100%',
              borderCollapse: 'collapse',
              fontSize: 13.5,
            }}
          >
            <thead>
              <tr style={{ background: 'var(--bg-2)' }}>
                {['Fonte', 'Última execução', 'Duração', 'Registros', 'Status', ''].map((h) => (
                  <th
                    key={h}
                    style={{
                      padding: '10px 14px',
                      textAlign: 'left',
                      fontWeight: 600,
                      fontSize: 12,
                      color: 'var(--ink-3)',
                      letterSpacing: '0.04em',
                      whiteSpace: 'nowrap',
                    }}
                  >
                    {h}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {etlLatest.map((row) => {
                const variant = etlBadgeVariant(row.status)
                const isFailed = variant === 'err'
                return (
                  <tr
                    key={row.fonte}
                    style={{ borderTop: '1px solid var(--line)' }}
                  >
                    <td style={{ padding: '10px 14px', fontWeight: 500, color: 'var(--ink)' }}>
                      {row.fonte}
                    </td>
                    <td style={{ padding: '10px 14px', color: 'var(--ink-2)', fontFamily: 'var(--font-mono)', fontSize: 12 }}>
                      {fmtDate(row.criado_em)}
                    </td>
                    <td style={{ padding: '10px 14px', color: 'var(--ink-3)', fontFamily: 'var(--font-mono)', fontSize: 12 }}>
                      {fmtDuration(row.duracao_ms)}
                    </td>
                    <td style={{ padding: '10px 14px', color: 'var(--ink-2)', fontFamily: 'var(--font-mono)', fontSize: 12 }}>
                      {fmtNum(row.registros)}
                    </td>
                    <td style={{ padding: '10px 14px' }}>
                      <StatusBadge variant={variant} label={row.status} />
                    </td>
                    <td style={{ padding: '10px 14px' }}>
                      {isFailed && (
                        <a
                          href={`/admin/etl?fonte=${encodeURIComponent(row.fonte)}`}
                          style={{
                            fontSize: 12,
                            color: 'var(--brand)',
                            textDecoration: 'none',
                            fontWeight: 500,
                            border: '1px solid var(--line)',
                            borderRadius: 5,
                            padding: '3px 10px',
                            display: 'inline-block',
                          }}
                        >
                          Ver ETL →
                        </a>
                      )}
                    </td>
                  </tr>
                )
              })}
            </tbody>
          </table>
        </div>
      )}
    </div>
  )
}

import { redirect } from 'next/navigation'
import Link from 'next/link'
import { getPgPool } from '@/lib/db/pool'

import { FeedCivico, type FeedEvento } from '@/components/painel/FeedCivico'
import { KpiStrip } from '@/components/painel/KpiStrip'
import { PainelHeader } from '@/components/painel/PainelHeader'
import { SeguindoList, type SeguidoPolitico } from '@/components/painel/SeguindoList'
import { getCurrentUser } from '@/lib/auth/current-user'

type AcompanhamentoRow = {
  politico_id: string
  tipo: string
}

type PoliticoResumoRow = {
  id: string
  slug: string
  nome: string
  nome_eleitoral: string | null
  cargo: string
  uf: string | null
  foto_url: string | null
  presenca_pct_atual: number | null
  partidos: { sigla: string | null } | { sigla: string | null }[] | null
}

type PerfilRow = {
  nome: string | null
}

type VotacaoRow = {
  id: string
  politico_id: string
  data: string
  hora: string | null
  voto: string
  descricao_simples: string | null
  proposicao: string | null
}

type GastoRow = {
  id: string
  politico_id: string
  valor: number | string | null
  categoria: string | null
  fornecedor: string | null
  mes: number
  ano: number
  descricao: string | null
  criado_em: string | null
}
import { normalizarPolitico } from '@/lib/utils/politicos'


function votoChip(voto: string): 'SIM' | 'NÃO' | 'ABS' | 'AUS' | 'OBS' {
  const v = voto.toLowerCase()
  if (v === 'sim') return 'SIM'
  if (v === 'nao') return 'NÃO'
  if (v === 'abstencao') return 'ABS'
  if (v === 'ausente') return 'AUS'
  return 'OBS'
}

function tipoBadge(voto: string): FeedEvento['badgeTipo'] {
  const v = voto.toLowerCase()
  if (v === 'sim') return 'VOTAÇÃO_POS'
  if (v === 'nao') return 'VOTAÇÃO_NEG'
  return 'VOTAÇÃO_NEUTRA'
}

function inicioDiaISO(data: Date): string {
  const d = new Date(data)
  d.setHours(0, 0, 0, 0)
  return d.toISOString()
}

function seteDiasAtrasISO(data: Date): string {
  const d = new Date(data)
  d.setDate(d.getDate() - 7)
  d.setHours(0, 0, 0, 0)
  return d.toISOString()
}

function trintaDiasAtrasISO(data: Date): string {
  const d = new Date(data)
  d.setDate(d.getDate() - 30)
  d.setHours(0, 0, 0, 0)
  return d.toISOString()
}

function isFeedEvento(item: FeedEvento | null): item is FeedEvento {
  return item !== null
}

export default async function PainelPage() {
  const db = getPgPool()
  const currentUser = await getCurrentUser()

  if (!currentUser) {
    redirect('/login')
  }

  const agora = new Date()
  const dataSeteDias = seteDiasAtrasISO(agora)
  const inicioHoje = inicioDiaISO(agora)

  const { rows: perfilRows } = await db.query<PerfilRow>(
    'SELECT nome FROM perfis WHERE id = $1 LIMIT 1',
    [currentUser.perfilId],
  )
  const perfil = perfilRows[0] ?? null

  let acompanhamentosRows: AcompanhamentoRow[] = []
  try {
    const { rows } = await db.query<AcompanhamentoRow>(
      'SELECT politico_id, tipo FROM acompanhamentos WHERE usuario_id = $1',
      [currentUser.perfilId],
    )
    acompanhamentosRows = rows
  } catch {
    // Mantem o painel funcional sem quebrar a renderizacao em dev.
  }

  const acompanhamentos = acompanhamentosRows ?? []
  const idsAcompanhados = Array.from(new Set(acompanhamentos.map((a) => a.politico_id).filter(Boolean)))
  const acompanhamentosTipoMap = new Map(acompanhamentos.map((a) => [a.politico_id, a.tipo]))

  let politicosRows: PoliticoResumoRow[] = []
  if (idsAcompanhados.length) {
    try {
      const { rows } = await db.query<PoliticoResumoRow>(
        `SELECT
           p.id,
           p.slug,
           p.nome,
           p.nome_eleitoral,
           p.cargo,
           p.uf,
           p.foto_url,
           p.presenca_pct_atual,
           CASE WHEN pa.sigla IS NULL THEN NULL ELSE json_build_object('sigla', pa.sigla) END AS partidos
         FROM politicos p
         LEFT JOIN partidos pa ON pa.id = p.partido_id
         WHERE p.id = ANY($1::uuid[])`,
        [idsAcompanhados],
      )
      politicosRows = rows
    } catch {
      // Mantem o painel funcional sem quebrar a renderizacao em dev.
    }
  }

  const politicosMap = new Map(politicosRows.map((p) => [p.id, p] as const))

  const seguindo = idsAcompanhados
    .map((id) => {
      const politico = politicosMap.get(id)
      if (!politico) return null
      const item = normalizarPolitico(politico)
      if (!item) return null
      item.tipo = (acompanhamentosTipoMap.get(id) || 'seguir') as 'voto' | 'seguir'
      return item
    })
    .filter((p): p is SeguidoPolitico => p !== null)

  const ids = seguindo.map((p) => p.id)
  const politicosPorId = new Map(seguindo.map((p) => [p.id, p] as const))

  // Cálculo da média de presença em memória
  const politicosComPresenca = seguindo.filter((p) => p.presencaPctAtual !== null)
  const mediaPresenca = politicosComPresenca.length > 0
    ? politicosComPresenca.reduce((acc, p) => acc + (p.presencaPctAtual ?? 0), 0) / politicosComPresenca.length
    : null

  let totalGastos30d = 0
  let votacoes7d: VotacaoRow[] = []
  let gastos7d: GastoRow[] = []
  let sugestoes: SeguidoPolitico[] = []
  let gastosIndividuais: Record<string, number> = {}

  if (ids.length > 0) {
    const dataTrintaDias = trintaDiasAtrasISO(agora)
    const [{ rows: votacoesData }, { rows: gastosData }, { rows: totalGastosRows }] = await Promise.all([
      db.query<VotacaoRow>(
        `SELECT id, politico_id, data::text AS data, hora::text AS hora, voto, descricao_simples, proposicao
         FROM votacoes
         WHERE politico_id = ANY($1::uuid[])
           AND data >= $2
         ORDER BY data DESC
         LIMIT 20`,
        [ids, dataSeteDias],
      ),
      db.query<GastoRow>(
        `SELECT id, politico_id, valor, categoria, fornecedor, mes, ano, descricao, criado_em::text AS criado_em
         FROM gastos
         WHERE politico_id = ANY($1::uuid[])
           AND criado_em >= $2
         ORDER BY criado_em DESC
         LIMIT 20`,
        [ids, dataSeteDias],
      ),
      db.query<{ politico_id: string; total: number | string | null }>(
        `SELECT politico_id, SUM(COALESCE(valor::numeric, 0)) AS total
         FROM gastos
         WHERE politico_id = ANY($1::uuid[])
           AND criado_em >= $2
         GROUP BY politico_id`,
        [ids, dataTrintaDias],
      ),
    ])

    votacoes7d = votacoesData ?? []
    gastos7d = gastosData ?? []
    
    gastosIndividuais = Object.fromEntries(
      (totalGastosRows ?? []).map((r) => [r.politico_id, Number(r.total || 0)] as const)
    )
    totalGastos30d = Object.values(gastosIndividuais).reduce((acc, val) => acc + val, 0)

    // Injeta os gastos individuais nos políticos seguidos
    for (const p of seguindo) {
      p.gastos30d = gastosIndividuais[p.id] ?? 0
    }
  } else {
    // Buscar sugestões de políticos caso o usuário não siga ninguém
    try {
      const { rows: sugeridosRows } = await db.query<PoliticoResumoRow>(
        `SELECT
           p.id,
           p.slug,
           p.nome,
           p.nome_eleitoral,
           p.cargo,
           p.uf,
           p.foto_url,
           p.presenca_pct_atual,
           CASE WHEN pa.sigla IS NULL THEN NULL ELSE json_build_object('sigla', pa.sigla) END AS partidos
         FROM politicos p
         LEFT JOIN partidos pa ON pa.id = p.partido_id
         WHERE p.situacao = 'ativo' AND p.foto_url IS NOT NULL
         ORDER BY p.presenca_pct_atual DESC NULLS LAST
         LIMIT 5`
      )
      sugestoes = sugeridosRows
        .map((r) => normalizarPolitico(r))
        .filter((p): p is SeguidoPolitico => p !== null)
    } catch (err) {
      console.error('Erro ao buscar sugestões de políticos:', err)
    }
  }

  const eventosVotacao = votacoes7d
    .map((row) => {
      const politico = politicosPorId.get(row.politico_id)
      if (!politico) return null
      const isVoto = acompanhamentosTipoMap.get(row.politico_id) === 'voto'
      const item: FeedEvento = {
        id: `vot-${row.id}`,
        tipo: 'VOTAÇÃO',
        badgeTipo: tipoBadge(row.voto),
        voto: votoChip(row.voto),
        timestamp: row.data,
        hora: row.hora ?? '00:00',
        politico,
        titulo: row.proposicao ?? 'Votação em plenário',
        descricao: row.descricao_simples ?? 'Sem descrição simplificada.',
        contexto: `Voto registrado: ${row.voto}`,
        source: 'camara/senado',
        isVoto,
      }
      return item
    })
    .filter(isFeedEvento)

  const eventosGasto = gastos7d
    .map((row) => {
      const politico = politicosPorId.get(row.politico_id)
      if (!politico) return null
      const isVoto = acompanhamentosTipoMap.get(row.politico_id) === 'voto'
      const item: FeedEvento = {
        id: `gst-${row.id}`,
        tipo: 'GASTOS',
        badgeTipo: 'ALERTA_GASTOS',
        voto: null,
        timestamp: row.criado_em ?? `${row.ano}-${String(row.mes).padStart(2, '0')}-01`,
        hora: '00:00',
        politico,
        titulo: row.categoria ?? 'Gasto parlamentar',
        descricao:
          row.descricao ??
          `Fornecedor: ${row.fornecedor ?? 'não informado'} · Valor: ${Number(row.valor || 0).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}`,
        contexto: `Mês ${String(row.mes).padStart(2, '0')}/${row.ano}`,
        source: 'portal-transparencia',
        isVoto,
      }
      return item
    })
    .filter(isFeedEvento)

  const feedEventos = [...eventosVotacao, ...eventosGasto]
    .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime())
    .slice(0, 40)

  const eventosHojeVot = votacoes7d.filter((v) => new Date(v.data).getTime() >= new Date(inicioHoje).getTime()).length
  const eventosHojeGasto = gastos7d.filter((g) => {
    if (!g.criado_em) return false
    return new Date(g.criado_em).getTime() >= new Date(inicioHoje).getTime()
  }).length

  const depCount = seguindo.filter((p) => p.cargo.toLowerCase().includes('deput')).length
  const senCount = seguindo.filter((p) => p.cargo.toLowerCase().includes('sen')).length

  return (
    <div style={{ background: 'var(--bg)', minHeight: '100%', position: 'relative', overflow: 'hidden' }}>
      {/* Glow background circles */}
      <div style={{
        position: 'absolute',
        top: '-10%',
        left: '10%',
        width: '400px',
        height: '400px',
        borderRadius: '50%',
        background: 'radial-gradient(circle, rgba(99, 102, 241, 0.15) 0%, rgba(99, 102, 241, 0) 70%)',
        filter: 'blur(60px)',
        pointerEvents: 'none',
        zIndex: 0,
      }} />
      <div style={{
        position: 'absolute',
        bottom: '20%',
        right: '-5%',
        width: '500px',
        height: '500px',
        borderRadius: '50%',
        background: 'radial-gradient(circle, rgba(236, 72, 153, 0.1) 0%, rgba(236, 72, 153, 0) 70%)',
        filter: 'blur(80px)',
        pointerEvents: 'none',
        zIndex: 0,
      }} />

      <div className="painel-page-layout" style={{ position: 'relative', zIndex: 1, padding: '28px 24px', display: 'flex', gap: 24, alignItems: 'flex-start' }}>
        <div style={{ flex: 1.6, minWidth: 0 }}>
          <PainelHeader
            email={currentUser.email ?? 'usuario@meuspoliticos.com.br'}
            nomeUsuario={(perfil?.nome as string | null) ?? currentUser.email ?? 'cidadão'}
            atualizacoesCount={feedEventos.length}
          />

          <KpiStrip
            politicosSeguidos={seguindo.length}
            depCount={depCount}
            senCount={senCount}
            eventosHoje={eventosHojeVot + eventosHojeGasto}
            totalGastos30d={totalGastos30d}
            mediaPresenca={mediaPresenca}
          />

          {seguindo.length > 0 && (
            <div style={{
              marginTop: 20,
              background: 'var(--panel)',
              border: '1px solid var(--line)',
              borderRadius: 14,
              padding: '20px 24px',
              boxShadow: '0 4px 20px rgba(0,0,0,0.15)',
            }}>
              <h2 style={{
                margin: '0 0 16px',
                fontSize: 10,
                fontFamily: 'var(--font-mono)',
                fontWeight: 700,
                color: 'var(--ink-3)',
                letterSpacing: '0.08em',
                textTransform: 'uppercase',
              }}>
                Desempenho Individual dos Políticos Monitorados
              </h2>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))', gap: 16 }}>
                {seguindo.map((p) => {
                  const presenceColor = p.presencaPctAtual === null ? 'var(--ink-3)' : p.presencaPctAtual > 85 ? 'var(--pos)' : p.presencaPctAtual >= 70 ? 'var(--warn)' : 'var(--neg)'
                  const presencePct = p.presencaPctAtual ?? 0
                  return (
                    <div
                      key={p.id}
                      style={{
                        background: 'rgba(30, 41, 59, 0.25)',
                        border: '1px solid var(--line)',
                        borderRadius: 10,
                        padding: 16,
                        display: 'flex',
                        flexDirection: 'column',
                        gap: 14,
                      }}
                    >
                      <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
                        {p.fotoUrl ? (
                          <img
                            src={p.fotoUrl}
                            alt={p.nomeEleitoral}
                            style={{ width: 36, height: 36, borderRadius: 999, objectFit: 'cover', border: '1px solid var(--line)' }}
                          />
                        ) : (
                          <div style={{ width: 36, height: 36, borderRadius: 999, background: 'var(--brand)', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 'bold', fontSize: 11 }}>
                            {p.nomeEleitoral.charAt(0)}
                          </div>
                        )}
                        <div>
                          <Link href={`/painel/politicos/${p.slug}`} style={{ fontSize: 13.5, fontWeight: 700, color: 'var(--ink)', textDecoration: 'none' }}>
                            {p.nomeEleitoral}
                          </Link>
                          <div style={{ fontSize: 11, color: 'var(--ink-3)' }}>{p.partido}-{p.uf} · {p.cargo}</div>
                        </div>
                      </div>

                      <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 11 }}>
                          <span style={{ color: 'var(--ink-3)' }}>PRESENÇA PLENÁRIA</span>
                          <span style={{ fontWeight: 700, color: presenceColor }}>{p.presencaPctAtual !== null ? `${Math.round(presencePct)}%` : '—'}</span>
                        </div>
                        <div style={{ height: 4, background: 'var(--bg)', borderRadius: 2, overflow: 'hidden' }}>
                          <div style={{ height: '100%', width: `${presencePct}%`, background: presenceColor, borderRadius: 2 }} />
                        </div>
                      </div>

                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderTop: '1px solid var(--line)', paddingTop: 10 }}>
                        <span style={{ fontSize: 11, color: 'var(--ink-3)' }}>GASTOS (ÚLT. 30 DIAS)</span>
                        <span style={{ fontSize: 13, fontWeight: 700, color: 'var(--brand-2)' }}>
                          {(p.gastos30d ?? 0).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 })}
                        </span>
                      </div>
                    </div>
                  )
                })}
              </div>
            </div>
          )}

          <div style={{ marginTop: 20 }}>
            <FeedCivico feedEventos={feedEventos} totalSeguidos={seguindo.length} sugestoes={sugestoes} />
          </div>
        </div>

        <div className="painel-sidebar" style={{ width: 320, minWidth: 320, display: 'flex', flexDirection: 'column', gap: 16 }}>
          <SeguindoList seguindo={seguindo} />
        </div>
      </div>

      <style>{`
        @media (max-width: 1024px) {
          .painel-page-layout {
            flex-direction: column !important;
            padding: 20px 16px !important;
            gap: 20px !important;
          }
          .painel-sidebar {
            width: 100% !important;
            min-width: 0 !important;
          }
        }
        @media (max-width: 640px) {
          .feed-item-grid {
            grid-template-columns: 1fr !important;
          }
        }
      `}</style>
    </div>
  )
}

'use client'

import Link from 'next/link'
import { useState, useEffect, useRef } from 'react'
import { X, Check, RefreshCw } from 'lucide-react'

// ─── Grid background inline (com linhas sutis baseadas em var(--line)) ────────
const GRID_BG: React.CSSProperties = {
  backgroundImage: 'linear-gradient(var(--line) 1px, transparent 1px), linear-gradient(90deg, var(--line) 1px, transparent 1px)',
  backgroundSize: '60px 60px',
}

type TipoApoio = 'mensal' | 'unica'

export default function ApoioPage() {
  const [pagamentoEmAndamento, setPagamentoEmAndamento] = useState<TipoApoio | null>(null)
  const [erroPagamento, setErroPagamento] = useState<string | null>(null)

  // Estados do Apoio Inline
  const [modalTipo, setModalTipo] = useState<TipoApoio>('mensal')
  const [modalValor, setModalValor] = useState<number>(25)
  const [isCustomValor, setIsCustomValor] = useState(false)

  // Etapa do Checkout
  const [etapa, setEtapa] = useState<'cadastro' | 'pagamento' | 'sucesso'>('cadastro')
  const [formaPagamento, setFormaPagamento] = useState<'pix' | 'cartao'>('pix')

  // Informações do Apoiador
  const [nome, setNome] = useState('')
  const [email, setEmail] = useState('')
  const [cpfCnpj, setCpfCnpj] = useState('')
  const [telefone, setTelefone] = useState('')

  // Informações do Cartão de Crédito
  const [cartaoHolderName, setCartaoHolderName] = useState('')
  const [cartaoNumber, setCartaoNumber] = useState('')
  const [cartaoExpiry, setCartaoExpiry] = useState('')
  const [cartaoCvv, setCartaoCvv] = useState('')
  const [cartaoPostalCode, setCartaoPostalCode] = useState('')
  const [cartaoAddressNumber, setCartaoAddressNumber] = useState('')

  // Retorno da Cobrança Pix
  const [pixQrCode, setPixQrCode] = useState('')
  const [pixCopiaCola, setPixCopiaCola] = useState('')
  const [paymentId, setPaymentId] = useState('')
  const [copiado, setCopiado] = useState(false)

  const pollingRef = useRef<NodeJS.Timeout | null>(null)

  // Limpar polling se desmontar
  useEffect(() => {
    return () => pararPollingPix()
  }, [])

  const iniciarPollingPix = (payId: string) => {
    if (pollingRef.current) clearInterval(pollingRef.current)
    pollingRef.current = setInterval(async () => {
      try {
        const response = await fetch('/api/apoio/verificar-pagamento', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ paymentId: payId })
        })
        const data = await response.json()
        if (response.ok && data.paid) {
          pararPollingPix()
          setEtapa('sucesso')
        }
      } catch (err) {
        console.warn('Erro ao verificar status do Pix:', err)
      }
    }, 5000)
  }

  const pararPollingPix = () => {
    if (pollingRef.current) {
      clearInterval(pollingRef.current)
      pollingRef.current = null
    }
  }

  const handleVerificarPixManual = async () => {
    if (!paymentId) return
    setPagamentoEmAndamento(modalTipo)
    setErroPagamento(null)
    try {
      const response = await fetch('/api/apoio/verificar-pagamento', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ paymentId })
      })
      const data = await response.json()
      if (response.ok && data.paid) {
        pararPollingPix()
        setEtapa('sucesso')
      } else {
        setErroPagamento('Pagamento ainda não detectado. Se você já pagou, aguarde alguns instantes.')
      }
    } catch {
      setErroPagamento('Erro ao conectar com o servidor para verificar o pagamento.')
    } finally {
      setPagamentoEmAndamento(null)
    }
  }

  const handleCopiarPix = () => {
    if (!pixCopiaCola) return
    navigator.clipboard.writeText(pixCopiaCola)
    setCopiado(true)
    setTimeout(() => setCopiado(false), 2000)
  }

  // Máscaras de entrada
  const handleCpfCnpjChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const raw = e.target.value.replace(/\D/g, '')
    if (raw.length > 14) return

    let formatted = raw
    if (raw.length <= 11) {
      formatted = raw
        .replace(/(\d{3})(\d)/, '$1.$2')
        .replace(/(\d{3})(\d)/, '$1.$2')
        .replace(/(\d{3})(\d{1,2})$/, '$1-$2')
    } else {
      formatted = raw
        .replace(/^(\d{2})(\d)/, '$1.$2')
        .replace(/^(\d{2})\.(\d{3})(\d)/, '$1.$2.$3')
        .replace(/\.(\d{3})(\d)/, '.$1/$2')
        .replace(/(\d{4})(\d{1,2})$/, '$1-$2')
    }
    setCpfCnpj(formatted)
  }

  const handleTelefoneChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const raw = e.target.value.replace(/\D/g, '')
    if (raw.length > 11) return

    let formatted = raw
    if (raw.length <= 10) {
      formatted = raw
        .replace(/(\d{2})(\d)/, '($1) $2')
        .replace(/(\d{4})(\d{1,4})$/, '$1-$2')
    } else {
      formatted = raw
        .replace(/(\d{2})(\d)/, '($1) $2')
        .replace(/(\d{5})(\d{1,4})$/, '$1-$2')
    }
    setTelefone(formatted)
  }

  const handleValidadeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const raw = e.target.value.replace(/\D/g, '')
    if (raw.length > 4) return
    let formatted = raw
    if (raw.length > 2) {
      formatted = `${raw.slice(0, 2)}/${raw.slice(2, 4)}`
    }
    setCartaoExpiry(formatted)
  }

  const handleNumeroCartaoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const raw = e.target.value.replace(/\D/g, '')
    if (raw.length > 16) return
    const formatted = raw.replace(/(\d{4})(?=\d)/g, '$1 ')
    setCartaoNumber(formatted)
  }

  const handlePostalCodeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const raw = e.target.value.replace(/\D/g, '')
    if (raw.length > 8) return
    const formatted = raw.replace(/(\d{5})(\d{1,3})$/, '$1-$2')
    setCartaoPostalCode(formatted)
  }

  async function handleConfirmarApoioInline(e: React.FormEvent) {
    e.preventDefault()
    if (!modalTipo) return

    if (!nome.trim()) {
      setErroPagamento('Informe seu nome completo.')
      return
    }
    if (!email.trim() || !email.includes('@')) {
      setErroPagamento('Informe um e-mail válido.')
      return
    }
    const cleanCpf = cpfCnpj.replace(/\D/g, '')
    if (cleanCpf.length !== 11 && cleanCpf.length !== 14) {
      setErroPagamento('Informe um CPF (11 dígitos) ou CNPJ (14 dígitos) válido.')
      return
    }
    const cleanPhone = telefone.replace(/\D/g, '')
    if (cleanPhone.length < 10) {
      setErroPagamento('Informe um telefone válido com DDD.')
      return
    }

    if (formaPagamento === 'cartao') {
      if (!cartaoHolderName.trim()) {
        setErroPagamento('Informe o nome do titular do cartão.')
        return
      }
      if (cartaoNumber.replace(/\s/g, '').length < 15) {
        setErroPagamento('Informe um número de cartão válido.')
        return
      }
      if (!cartaoExpiry.includes('/') || cartaoExpiry.length < 5) {
        setErroPagamento('Informe a validade no formato MM/AA.')
        return
      }
      if (cartaoCvv.trim().length < 3) {
        setErroPagamento('Informe o código de segurança (CVV).')
        return
      }
      if (cartaoPostalCode.replace(/\D/g, '').length < 8) {
        setErroPagamento('Informe um CEP de faturamento válido.')
        return
      }
      if (!cartaoAddressNumber.trim()) {
        setErroPagamento('Informe o número do endereço.')
        return
      }
    }

    setPagamentoEmAndamento(modalTipo)
    setErroPagamento(null)

    try {
      const payload = {
        nome: nome.trim(),
        email: email.trim().toLowerCase(),
        cpfCnpj: cleanCpf,
        telefone: cleanPhone,
        tipo: modalTipo,
        valor: modalValor,
        formaPagamento,
        ...(formaPagamento === 'cartao' ? {
          cartaoInfo: {
            holderName: cartaoHolderName.trim(),
            number: cartaoNumber.replace(/\s/g, ''),
            expiry: cartaoExpiry,
            ccv: cartaoCvv.trim(),
            postalCode: cartaoPostalCode.replace(/\D/g, ''),
            addressNumber: cartaoAddressNumber.trim()
          }
        } : {})
      }

      const response = await fetch('/api/apoio/criar-link', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      })

      const data = await response.json()

      if (!response.ok) {
        setErroPagamento(data.error ?? 'Não foi possível processar seu pagamento. Verifique seus dados e tente novamente.')
        return
      }

      if (formaPagamento === 'pix') {
        setPixQrCode(data.qrCode)
        setPixCopiaCola(data.copiaCola)
        setPaymentId(data.paymentId)
        iniciarPollingPix(data.paymentId)
      } else {
        setEtapa('sucesso')
      }
    } catch {
      setErroPagamento('Falha de conexão ao processar pagamento.')
    } finally {
      setPagamentoEmAndamento(null)
    }
  }

  const buttonBase: React.CSSProperties = {
    display: 'block',
    width: '100%',
    padding: '14px 0',
    borderRadius: 12,
    fontSize: 15,
    fontWeight: 700,
    textAlign: 'center',
    cursor: 'pointer',
    transition: 'all 0.15s ease-in-out',
  }

  return (
    <div style={{ background: 'var(--bg)', color: 'var(--ink)', position: 'relative', overflow: 'hidden', minHeight: '100vh' }}>

      {/* Halos/Glows decorativos em segundo plano */}
      <div style={{
        position: 'absolute',
        top: '-5%',
        left: '10%',
        width: '500px',
        height: '500px',
        borderRadius: '50%',
        background: 'radial-gradient(circle, rgba(99, 102, 241, 0.12) 0%, rgba(99, 102, 241, 0) 70%)',
        filter: 'blur(80px)',
        pointerEvents: 'none',
        zIndex: 0,
      }} />
      <div style={{
        position: 'absolute',
        bottom: '25%',
        right: '-10%',
        width: '600px',
        height: '600px',
        borderRadius: '50%',
        background: 'radial-gradient(circle, rgba(236, 72, 153, 0.08) 0%, rgba(236, 72, 153, 0) 70%)',
        filter: 'blur(100px)',
        pointerEvents: 'none',
        zIndex: 0,
      }} />

      {/* ── Seção de Apoio Principal (Direct & Fluid Checkout) ───────────────── */}
      <section id="apoiar" style={{ background: 'transparent', padding: '128px 24px 80px', position: 'relative', zIndex: 1 }}>
        <div style={{ maxWidth: 1000, margin: '0 auto' }}>

          <div style={{ textAlign: 'center', marginBottom: 40 }}>
            <h2 style={{
              fontSize: 42, fontWeight: 900, margin: '0 0 16px',
              letterSpacing: '-0.03em',
              lineHeight: 1.15,
              color: 'var(--ink)',
              fontFamily: 'var(--font-display)',
            }}>
              Seja um mantenedor da <span style={{
                background: 'linear-gradient(135deg, var(--brand-2) 0%, #a855f7 50%, #f43f5e 100%)',
                WebkitBackgroundClip: 'text',
                WebkitTextFillColor: 'transparent',
              }}>independência</span>
            </h2>
            <p style={{ fontSize: 15, color: 'var(--ink-3)', margin: '0 auto', maxWidth: 460, lineHeight: 1.6 }}>
              Escolha o valor e a frequência do seu apoio para manter o portal Meus Políticos 100% independente.
            </p>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
            <div className="lg:col-span-7" style={{
              background: 'var(--panel)',
              border: '1px solid var(--line)',
              borderRadius: 24,
              padding: '40px 32px',
              boxShadow: '0 10px 40px rgba(0,0,0,0.3)',
              position: 'relative',
              zIndex: 2
            }}>

            {/* FORMULÁRIO DE CADASTRO E PAGAMENTO */}
            {etapa !== 'sucesso' && !pixQrCode && (
              <form onSubmit={handleConfirmarApoioInline} style={{ display: 'flex', flexDirection: 'column', gap: 24 }}>

                {/* Frequência do Apoio */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                  <span style={{ fontSize: 11, fontWeight: 700, color: 'var(--ink-3)', fontFamily: 'var(--font-mono)', letterSpacing: '0.05em' }}>
                    FREQUÊNCIA DO APOIO
                  </span>
                  <div style={{ display: 'flex', gap: 10 }}>
                    <button
                      type="button"
                      onClick={() => {
                        setModalTipo('mensal')
                        if (!isCustomValor) setModalValor(25)
                      }}
                      style={{
                        flex: 1,
                        padding: '12px',
                        borderRadius: 10,
                        border: modalTipo === 'mensal' ? '2px solid var(--brand-2)' : '1px solid var(--line)',
                        background: modalTipo === 'mensal' ? 'rgba(99, 102, 241, 0.1)' : 'rgba(30, 41, 59, 0.2)',
                        color: 'var(--ink)',
                        fontWeight: 700,
                        fontSize: 14,
                        cursor: 'pointer',
                        transition: 'all 0.2s'
                      }}
                    >
                      Mensal (Recorrente)
                    </button>
                    <button
                      type="button"
                      onClick={() => {
                        setModalTipo('unica')
                        if (!isCustomValor) setModalValor(50)
                      }}
                      style={{
                        flex: 1,
                        padding: '12px',
                        borderRadius: 10,
                        border: modalTipo === 'unica' ? '2px solid var(--brand-2)' : '1px solid var(--line)',
                        background: modalTipo === 'unica' ? 'rgba(99, 102, 241, 0.1)' : 'rgba(30, 41, 59, 0.2)',
                        color: 'var(--ink)',
                        fontWeight: 700,
                        fontSize: 14,
                        cursor: 'pointer',
                        transition: 'all 0.2s'
                      }}
                    >
                      Único (Uma vez)
                    </button>
                  </div>
                </div>

                {/* Seleção do Valor */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                  <span style={{ fontSize: 11, fontWeight: 700, color: 'var(--ink-3)', fontFamily: 'var(--font-mono)', letterSpacing: '0.05em' }}>
                    VALOR DO APOIO
                  </span>
                  <div style={{ display: 'grid', gridTemplateColumns: 'repeat(5, 1fr)', gap: 8 }}>
                    {[10, 25, 50, 100].map(val => (
                      <button
                        key={val}
                        type="button"
                        onClick={() => {
                          setModalValor(val)
                          setIsCustomValor(false)
                        }}
                        style={{
                          padding: '10px 0',
                          borderRadius: 8,
                          border: (!isCustomValor && modalValor === val) ? '2px solid var(--brand-2)' : '1px solid var(--line)',
                          background: (!isCustomValor && modalValor === val) ? 'rgba(99, 102, 241, 0.15)' : 'rgba(30, 41, 59, 0.2)',
                          color: 'var(--ink)',
                          fontWeight: 700,
                          fontSize: 14,
                          cursor: 'pointer',
                          transition: 'all 0.15s'
                        }}
                      >
                        R$ {val}
                      </button>
                    ))}
                    <button
                      type="button"
                      onClick={() => {
                        setIsCustomValor(true)
                        setModalValor(20) // padrão ao clicar em custom
                      }}
                      style={{
                        padding: '10px 0',
                        borderRadius: 8,
                        border: isCustomValor ? '2px solid var(--brand-2)' : '1px solid var(--line)',
                        background: isCustomValor ? 'rgba(99, 102, 241, 0.15)' : 'rgba(30, 41, 59, 0.2)',
                        color: 'var(--ink)',
                        fontWeight: 700,
                        fontSize: 14,
                        cursor: 'pointer',
                        transition: 'all 0.15s'
                      }}
                    >
                      Outro
                    </button>
                  </div>

                  {/* Input de Valor Customizado */}
                  {isCustomValor && (
                    <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginTop: 8 }}>
                      <span style={{ fontSize: 14, fontWeight: 700, color: 'var(--ink-2)' }}>R$</span>
                      <input
                        type="number"
                        min="5"
                        placeholder="Digite o valor"
                        value={modalValor || ''}
                        onChange={(e) => {
                          const val = parseFloat(e.target.value)
                          setModalValor(isNaN(val) ? 0 : val)
                        }}
                        className="input-apoio"
                        style={{ height: 38 }}
                      />
                      <span style={{ fontSize: 11, color: 'var(--ink-3)' }}>Mínimo de R$ 5</span>
                    </div>
                  )}
                </div>

                {/* Seus Dados */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
                  <span style={{ fontSize: 11, fontWeight: 700, color: 'var(--ink-3)', fontFamily: 'var(--font-mono)', letterSpacing: '0.05em' }}>
                    SEUS DADOS
                  </span>

                  <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
                    <input
                      type="text"
                      required
                      placeholder="Nome Completo"
                      value={nome}
                      onChange={(e) => setNome(e.target.value)}
                      className="input-apoio"
                    />
                  </div>

                  <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
                    <input
                      type="email"
                      required
                      placeholder="Endereço de E-mail"
                      value={email}
                      onChange={(e) => setEmail(e.target.value)}
                      className="input-apoio"
                    />
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <input
                      type="text"
                      required
                      placeholder="CPF / CNPJ"
                      value={cpfCnpj}
                      onChange={handleCpfCnpjChange}
                      className="input-apoio"
                    />
                    <input
                      type="text"
                      required
                      placeholder="WhatsApp (com DDD)"
                      value={telefone}
                      onChange={handleTelefoneChange}
                      className="input-apoio"
                    />
                  </div>
                </div>

                {/* Forma de Pagamento */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                  <span style={{ fontSize: 11, fontWeight: 700, color: 'var(--ink-3)', fontFamily: 'var(--font-mono)', letterSpacing: '0.05em' }}>
                    FORMA DE PAGAMENTO
                  </span>
                  <div style={{ display: 'flex', gap: 10 }}>
                    <button
                      type="button"
                      onClick={() => setFormaPagamento('pix')}
                      style={{
                        flex: 1,
                        padding: '12px',
                        borderRadius: 10,
                        border: formaPagamento === 'pix' ? '2px solid var(--brand-2)' : '1px solid var(--line)',
                        background: formaPagamento === 'pix' ? 'rgba(99, 102, 241, 0.1)' : 'rgba(30, 41, 59, 0.2)',
                        color: 'var(--ink)',
                        fontWeight: 700,
                        fontSize: 14,
                        cursor: 'pointer',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        gap: 8
                      }}
                    >
                      <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor" style={{ color: formaPagamento === 'pix' ? 'var(--brand-2)' : 'var(--ink-3)' }}>
                        <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-2h2v2zm0-4h-2V7h2v6z" />
                      </svg>
                      Pix
                    </button>
                    <button
                      type="button"
                      onClick={() => setFormaPagamento('cartao')}
                      style={{
                        flex: 1,
                        padding: '12px',
                        borderRadius: 10,
                        border: formaPagamento === 'cartao' ? '2px solid var(--brand-2)' : '1px solid var(--line)',
                        background: formaPagamento === 'cartao' ? 'rgba(99, 102, 241, 0.1)' : 'rgba(30, 41, 59, 0.2)',
                        color: 'var(--ink)',
                        fontWeight: 700,
                        fontSize: 14,
                        cursor: 'pointer',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        gap: 8
                      }}
                    >
                      <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" style={{ color: formaPagamento === 'cartao' ? 'var(--brand-2)' : 'var(--ink-3)' }}>
                        <rect x="2" y="5" width="20" height="14" rx="2" ry="2" />
                        <line x1="2" y1="10" x2="22" y2="10" />
                      </svg>
                      Cartão
                    </button>
                  </div>
                </div>

                {/* Dados do Cartão (inline se selecionado) */}
                {formaPagamento === 'cartao' && (
                  <div style={{ display: 'flex', flexDirection: 'column', gap: 12, borderTop: '1px solid var(--line)', paddingTop: 16 }}>
                    <span style={{ fontSize: 11, fontWeight: 700, color: 'var(--ink-3)', fontFamily: 'var(--font-mono)', letterSpacing: '0.05em' }}>
                      DADOS DO CARTÃO
                    </span>

                    <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
                      <input
                        type="text"
                        required
                        placeholder="Nome como escrito no cartão"
                        value={cartaoHolderName}
                        onChange={(e) => setCartaoHolderName(e.target.value.toUpperCase())}
                        className="input-apoio"
                      />
                    </div>

                    <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
                      <input
                        type="text"
                        required
                        placeholder="Número do Cartão"
                        value={cartaoNumber}
                        onChange={handleNumeroCartaoChange}
                        className="input-apoio"
                      />
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                      <input
                        type="text"
                        required
                        placeholder="Validade (MM/AA)"
                        value={cartaoExpiry}
                        onChange={handleValidadeChange}
                        className="input-apoio"
                      />
                      <input
                        type="text"
                        required
                        placeholder="CVV"
                        value={cartaoCvv}
                        onChange={(e) => {
                          const raw = e.target.value.replace(/\D/g, '')
                          if (raw.length <= 4) setCartaoCvv(raw)
                        }}
                        className="input-apoio"
                      />
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                      <input
                        type="text"
                        required
                        placeholder="CEP do Titular"
                        value={cartaoPostalCode}
                        onChange={handlePostalCodeChange}
                        className="input-apoio"
                      />
                      <input
                        type="text"
                        required
                        placeholder="Número do Endereço"
                        value={cartaoAddressNumber}
                        onChange={(e) => setCartaoAddressNumber(e.target.value)}
                        className="input-apoio"
                      />
                    </div>
                  </div>
                )}

                {erroPagamento && (
