                display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                paddingBottom: 12, borderBottom: '1px solid #e2e8f0',
              }}>
                <span style={{ fontSize: 14, color: '#45464d' }}>Foco Principal</span>
