                /* Fallback se não houver proposições */
                [
                  { label: 'PROJETO DE LEI', cor: '#8B5CF6', icon: '📋', title: 'Plenário Ulysses Guimarães', sub: 'Sessão Deliberativa Ordinária em tramitação' },
