                    boxShadow: '0 2px 8px rgba(0,0,0,0.1)', cursor: 'pointer', transition: 'all 0.2s'
                  }} className="hover:border-[#8B5CF6] hover:shadow-[0_0_20px_rgba(139,92,246,0.1)]">
