                    <div style={{ fontSize: 24, marginBottom: 8 }}>📝</div>
                    <div>
                      <div style={{ fontSize: 18, fontWeight: 800, color: 'var(--pos)' }}>
                        {consolidado.producaoLegislativa ? consolidado.producaoLegislativa.toLocaleString('pt-BR') : '—'}
