                      </div>
                    </div>
                  </div>
                </Link>

                {/* 6. Representação Federativa */}
                <Link href="/estado" style={{ textDecoration: 'none' }}>
                  <div style={{
                    background: 'var(--panel)', border: '1px solid var(--line)', borderRadius: 12, padding: 20,
