          {/* History table */}
          <div style={{ overflowX: 'auto', marginBottom: 16 }}>
            <table
              style={{
                width: '100%',
                borderCollapse: 'collapse',
                fontSize: 12.5,
                fontFamily: 'var(--font-mono)',
              }}
            >
              <thead>
                <tr style={{ background: 'var(--bg-2)' }}>
                  {['Data', 'Status', 'Duração', 'Registros', 'Mensagem'].map((h) => (
                    <th
