                  overflowY: 'auto',
                }}
              >
                {source.latest.mensagem}
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  )
}

'use client'

import { useRouter } from 'next/navigation'
import { useState, useTransition } from 'react'

type FeatureFlag = {
  id: string
  slug: string
  descricao: string | null
  ativo: boolean
  rollout_pct: number
  atualizado_em: string
}

interface FeatureFlagListProps {
  flags: FeatureFlag[]
}

const inputStyle = {
  padding: '8px 12px',
  fontSize: 13,
  border: '1px solid var(--line)',
  borderRadius: 5,
  outline: 'none',
  fontFamily: 'var(--font-sans)',
  background: 'var(--bg)',
  color: 'var(--ink)',
  width: '100%',
}

function fmtDate(iso: string): string {
  const d = new Date(iso)
  return d.toLocaleString('pt-BR', {
    day: '2-digit',
    month: '2-digit',
    year: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
  })
}

export function FeatureFlagList({ flags }: FeatureFlagListProps) {
  const router = useRouter()
  const [slug, setSlug] = useState('')
  const [descricao, setDescricao] = useState('')
  const [creating, setCreating] = useState(false)
  const [msg, setMsg] = useState<string | null>(null)
  const [isPending, startTransition] = useTransition()

  async function handleCreate(e: React.FormEvent) {
    e.preventDefault()
    if (!slug.trim()) return
    setCreating(true)
    setMsg(null)

    try {
      const res = await fetch('/api/admin/flags', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ slug, descricao }),
      })
      if (res.ok) {
        setSlug('')
        setDescricao('')
        setMsg('Feature flag criada!')
        startTransition(() => router.refresh())
      } else {
        const j = await res.json() as { error?: string }
        setMsg(`Erro: ${j.error ?? 'desconhecido'}`)
      }
    } catch {
      setMsg('Erro de rede.')
    } finally {
      setCreating(false)
    }
  }

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
      {/* Creation Form */}
      <div
        style={{
          background: 'var(--panel)',
          borderRadius: 10,
          boxShadow: '0 1px 4px rgba(0,0,0,0.06)',
          padding: '16px 20px',
        }}
      >
        <h3 style={{ fontSize: 13.5, fontWeight: 600, color: 'var(--ink)', marginBottom: 12 }}>
          Nova Feature Flag
        </h3>
        <form onSubmit={handleCreate} style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1.5fr', gap: 12 }}>
            <input
              type="text"
              placeholder="Slug da flag (ex: nova-busca)"
              value={slug}
              onChange={(e) => setSlug(e.target.value)}
              required
              style={inputStyle}
            />
            <input
              type="text"
              placeholder="Descrição (ex: Ativa novo algoritmo de busca)"
              value={descricao}
              onChange={(e) => setDescricao(e.target.value)}
              style={inputStyle}
            />
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginTop: 4 }}>
            <button
              type="submit"
              disabled={creating || isPending}
              style={{
                padding: '7px 16px',
                background: 'var(--brand)',
                color: '#fff',
                border: 'none',
                borderRadius: 6,
                fontSize: 12.5,
                fontWeight: 500,
                cursor: 'pointer',
                opacity: (creating || isPending) ? 0.7 : 1,
              }}
            >
              {creating ? 'Criando...' : 'Adicionar Flag'}
            </button>
            {msg && (
              <span
                style={{
                  fontSize: 12.5,
                  color: msg.startsWith('Erro') ? 'var(--neg)' : 'var(--pos)',
                  fontStyle: 'italic',
                }}
              >
                {msg}
              </span>
            )}
          </div>
        </form>
      </div>

      {/* Flag List */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
        {flags.map((flag) => (
          <FlagCard key={flag.id} flag={flag} />
        ))}
        {flags.length === 0 && (
          <div
            style={{
              background: 'var(--panel)',
              borderRadius: 10,
              boxShadow: '0 1px 4px rgba(0,0,0,0.06)',
              padding: '24px',
              textAlign: 'center',
              color: 'var(--ink-3)',
              fontSize: 14,
            }}
          >
            Nenhuma feature flag cadastrada.
          </div>
        )}
      </div>
    </div>
  )
}

function FlagCard({ flag }: { flag: FeatureFlag }) {
  const router = useRouter()
  const [ativo, setAtivo] = useState(flag.ativo)
  const [rollout, setRollout] = useState(flag.rollout_pct)
  const [saving, setSaving] = useState(false)
  const [msg, setMsg] = useState<string | null>(null)
  const [isPending, startTransition] = useTransition()

  async function handleToggle() {
    const newAtivo = !ativo
    setAtivo(newAtivo)
    setSaving(true)
    setMsg(null)
    try {
      const res = await fetch('/api/admin/flags', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ id: flag.id, ativo: newAtivo }),
      })
      if (res.ok) {
        setMsg('Salvo!')
        startTransition(() => router.refresh())
      } else {
        const j = await res.json() as { error?: string }
        setMsg(`Erro: ${j.error}`)
        setAtivo(!newAtivo) // revert
      }
    } catch {
      setMsg('Erro de rede')
      setAtivo(!newAtivo)
    } finally {
      setSaving(false)
    }
  }

  async function handleRolloutSave() {
    setSaving(true)
    setMsg(null)
    try {
      const res = await fetch('/api/admin/flags', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ id: flag.id, rollout_pct: rollout }),
      })
      if (res.ok) {
        setMsg('Salvo!')
        startTransition(() => router.refresh())
      } else {
        const j = await res.json() as { error?: string }
        setMsg(`Erro: ${j.error}`)
      }
    } catch {
      setMsg('Erro de rede')
    } finally {
      setSaving(false)
    }
  }

  async function handleDelete() {
    if (!window.confirm(`Tem certeza de que deseja excluir permanentemente a feature flag "${flag.slug}"?`)) {
      return
    }
    setSaving(true)
    setMsg(null)
    try {
      const res = await fetch('/api/admin/flags', {
        method: 'DELETE',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ id: flag.id }),
      })
      if (res.ok) {
        startTransition(() => router.refresh())
      } else {
        const j = await res.json() as { error?: string }
        setMsg(`Erro ao excluir: ${j.error}`)
        setSaving(false)
      }
    } catch {
      setMsg('Erro de rede ao excluir.')
      setSaving(false)
    }
  }

  return (
    <div
      style={{
        background: 'var(--panel)',
        borderRadius: 10,
        boxShadow: '0 1px 4px rgba(0,0,0,0.06)',
        padding: '16px 20px',
      }}
    >
      <div
        style={{
          display: 'flex',
          alignItems: 'flex-start',
          justifyContent: 'space-between',
          gap: 12,
