              borderRadius: 13,
              background: ativo ? 'var(--pos)' : 'var(--line-strong)',
              border: 'none',
              cursor: 'pointer',
              position: 'relative',
              transition: 'background 0.2s',
              opacity: saving ? 0.6 : 1,
            }}
          >
            <span
              style={{
                position: 'absolute',
                top: 3,
                left: ativo ? 23 : 3,
                width: 20,
                height: 20,
                borderRadius: '50%',
