          min={0}
          max={100}
          step={5}
          value={rollout}
          onChange={(e) => setRollout(Number(e.target.value))}
          style={{ flex: 1, accentColor: 'var(--brand)' }}
        />
        <span
          style={{
            fontSize: 13,
            fontFamily: 'var(--font-mono)',
            color: 'var(--ink-2)',
            minWidth: 36,
            textAlign: 'right',
          }}
        >
          {rollout}%
        </span>
        {rollout !== flag.rollout_pct && (
          <button
            onClick={handleRolloutSave}
            disabled={saving}
            style={{
              padding: '4px 12px',
              background: 'var(--brand)',
              color: '#fff',
              border: 'none',
              borderRadius: 5,
              fontSize: 12,
              fontWeight: 500,
              cursor: 'pointer',
              opacity: saving ? 0.7 : 1,
              flexShrink: 0,
            }}
          >
            Salvar
          </button>
        )}
      </div>

      {msg && (
        <div
          style={{
            marginTop: 8,
            fontSize: 12,
            color: msg.startsWith('Erro') ? 'var(--neg)' : 'var(--pos)',
            fontStyle: 'italic',
          }}
        >
          {msg}
        </div>
      )}
    </div>
  )
}

