            type="text"
            placeholder={canAdd ? 'Adicionar parlamentar...' : 'Limite de 5 atingido'}
            disabled={!canAdd}
            value={query}
            onChange={(e) => handleSearch(e.target.value)}
            style={{
              width: '100%',
              height: 40,
              padding: '0 36px 0 12px',
              border: '1px solid var(--line)',
              borderRadius: 8,
