            }}>
              <div style={{
                width: 20, height: 20, borderRadius: '50%', background: 'var(--brand-soft)',
                overflow: 'hidden', display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontSize: 9, fontWeight: 700, color: 'var(--brand)', flexShrink: 0,
