                  <Legend verticalAlign="top" height={36} iconType="circle" wrapperStyle={{ fontSize: 11 }} />
                  <Bar dataKey="Reservado (Empenhado)" fill="#8B5CF6" radius={[4, 4, 0, 0]} />
                  <Bar dataKey="Entregue (Pago)" fill="#10B981" radius={[4, 4, 0, 0]} />
