          </div>

          {/* Filtro Tipo */}
          <div className="md:col-span-2 flex flex-col gap-1.5">
            <label className="text-[10px] font-mono font-bold text-[#64748B] uppercase tracking-wider">Tipo</label>
            <select
              value={filters.tipo}
              onChange={(e) => atualizarFiltros({ tipo: e.target.value })}
