            >
              <option value="">Todos os tipos</option>
              {tiposDisponiveis.map(t => (
                <option key={t} value={t}>{t}</option>
              ))}
            </select>
          </div>

          {/* Filtro Função */}
          <div className="md:col-span-2 flex flex-col gap-1.5">
            <label className="text-[10px] font-mono font-bold text-[#64748B] uppercase tracking-wider">Área/Função</label>
            <select
              value={filters.funcao}
              onChange={(e) => atualizarFiltros({ funcao: e.target.value })}
              className="custom-select w-full"
            >
              <option value="">Todas as áreas</option>
              {funcoesDisponiveis.map(f => (
                <option key={f} value={f}>{f}</option>
              ))}
            </select>
          </div>
        </div>
      </div>

      {/* 📃 4. List of Emendas */}
      <div className="space-y-4">
        <div className="flex justify-between items-center">
          <span className="text-xs font-mono text-[#64748B]">
            {totalItems} emendas encontradas
          </span>
        </div>

        {emendasList.length === 0 ? (
          <div className="bg-[#1E293B] border border-[#334155] rounded-xl p-12 text-center flex flex-col items-center justify-center gap-3">
            <span className="material-symbols-outlined text-[32px] text-[#64748B]">search_off</span>
            <p className="text-sm font-bold text-white">Nenhum repasse encontrado</p>
            <p className="text-xs text-[#64748B] max-w-sm leading-normal">
              Tente redefinir seus filtros de busca ou digitar outro termo de pesquisa.
            </p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {emendasList.map((e) => {
              const executado = e.valor > 0 ? Math.round((e.valor_pago / e.valor) * 100) : 0

              // Resolver município destino amigável
              let destinoNome = e.municipio_nome
              let ufDestino = e.uf_municipio

              if (!destinoNome && e.municipio_destino) {
                const destLower = e.municipio_destino.toLowerCase()
                if (destLower.includes('múltiplo') || destLower.includes('multiplo')) {
                  destinoNome = 'Múltiplos municípios'
                  ufDestino = ''
                } else if (destLower.includes('nacional')) {
                  destinoNome = 'Nacional (Todo o país)'
                  ufDestino = ''
                } else if (destLower.includes('(uf)') || e.uf_destino === 'UF') {
                  const estadoNome = e.municipio_destino.replace(/\(uf\)/i, '').trim()
                  destinoNome = `Todo o estado (${estadoNome})`
                  ufDestino = ''
                } else {
                  const parts = e.municipio_destino.split(' - ')
                  if (parts.length === 2) {
                    destinoNome = parts[0].trim()
                    ufDestino = parts[1].trim()
                  } else {
                    destinoNome = e.municipio_destino
                  }
                }
              }

              const friendlyTitle = obterTituloAmigavel({
                funcao: e.funcao,
                municipio_nome: destinoNome,
                uf_municipio: ufDestino,
                municipio_destino: e.municipio_destino,
                uf_destino: e.uf_destino
              })

              return (
                <Link
                  key={e.id}
                  href={`/emendas/${e.id}`}
                  className="bg-[#1E293B] border border-[#334155] hover:border-[#8B5CF6]/40 p-4 rounded-xl flex flex-col justify-between shadow-sm transition-all hover:translate-y-[-2px] group"
                >
                  <div className="space-y-3">
                    {/* Header: Friendly Title & Value */}
                    <div className="flex justify-between items-start gap-4">
                      <h4 className="text-sm font-extrabold text-white group-hover:text-[#8B5CF6] transition-colors leading-snug line-clamp-2">
                        {friendlyTitle}
                      </h4>
                      <span className="font-mono text-xs text-[#34D399] font-bold flex-shrink-0 mt-0.5">
                        {formatCurrency(e.valor_pago)}
                      </span>
                    </div>

                    {/* Metadata: Author & Technical Details */}
                    <div className="flex flex-wrap items-center gap-x-2 gap-y-1 text-[11px] text-[#94A3B8] font-medium">
                      <span className="text-white font-bold">{e.autor_nome || 'Bancada / Coletivo'}</span>
                      <span className="text-[#475569]">•</span>
                      <span className="bg-[#0F172A] border border-[#334155] text-[9px] font-mono font-bold px-1.5 py-0.2 rounded text-[#94A3B8] inline-block">
                        Emenda {e.codigo_emenda}
                      </span>
                      <span className="text-[#475569]">•</span>
                      <span className="text-[#A78BFA] font-mono bg-[#4C1D95]/15 border border-[#4C1D95]/30 px-1 py-0.2 rounded">
                        {e.ano}
                      </span>
                    </div>
                  </div>

                  {/* Barra de Progresso Interna */}
                  <div className="border-t border-[#334155]/60 pt-3 mt-4 flex items-center justify-between text-[10px] text-[#64748B]">
                    <div className="flex-1 max-w-[120px] bg-[#0F172A] rounded-full h-1.5 overflow-hidden mr-3">
                      <div className="bg-[#10B981] h-full" style={{ width: `${executado}%` }} />
                    </div>
                    <span>Execução: {executado}%</span>
                  </div>
                </Link>
              )
            })}
          </div>
        )}

        {/* 🗺 Paginação */}
        {totalPages > 1 && (
          <div className="flex justify-center items-center gap-2 mt-8">
            <button
              onClick={() => irParaPagina(currentPage - 1)}
              disabled={currentPage <= 1}
              className="bg-[#1E293B] border border-[#334155] disabled:opacity-30 disabled:cursor-not-allowed hover:bg-slate-800 text-xs px-3 py-1.5 rounded-lg cursor-pointer"
            >
              Anterior
            </button>
            <span className="text-xs text-[#64748B] font-mono px-2">
              Página {currentPage} de {totalPages}
            </span>
            <button
              onClick={() => irParaPagina(currentPage + 1)}
              disabled={currentPage >= totalPages}
              className="bg-[#1E293B] border border-[#334155] disabled:opacity-30 disabled:cursor-not-allowed hover:bg-slate-800 text-xs px-3 py-1.5 rounded-lg cursor-pointer"
            >
              Próxima
            </button>
          </div>
        )}
      </div>

      {/* 🏛 5. State Assemblies Educational Card */}
      <section className="bg-gradient-to-br from-[#1E293B] via-[#0F172A] to-[#161D3A] border border-[#334155] rounded-2xl p-6 shadow-md relative overflow-hidden">
        <div className="absolute top-0 right-0 p-4 opacity-5 text-white">
          <span className="material-symbols-outlined text-[100px]">account_balance</span>
        </div>
        <div className="max-w-2xl space-y-3 relative z-10">
          <span className="bg-[#8B5CF6]/15 text-[#A78BFA] border border-[#8B5CF6]/30 text-[9px] font-mono font-bold uppercase tracking-wider px-2 py-0.5 rounded">
            Esfera Legislativa Estadual
          </span>
          <h4 className="text-white font-extrabold text-base tracking-tight">
            E as Emendas de Deputados Estaduais? (Assembleias Legislativas)
          </h4>
          <p className="text-xs text-[#94A3B8] leading-relaxed">
            As Assembleias Legislativas de cada estado (ALMG, ALESP, ALEP, etc.) também repassam milhões de reais em emendas estaduais enviadas por deputados estaduais. No entanto, por não serem centralizadas em um portal único federal, a coleta desses dados exige scrapers locais customizados.
          </p>
          <p className="text-xs text-[#CBD5E1] font-semibold leading-relaxed">
            💡 Nossa equipe está trabalhando no mapeamento das Assembleias Legislativas de São Paulo, Minas Gerais e Paraná para integrar o rastreamento estadual em breve!
          </p>
        </div>
      </section>
    </div>
  )
}

'use client'

import { useRouter, usePathname, useSearchParams } from 'next/navigation'
import { useState, useEffect, useTransition } from 'react'
import Link from 'next/link'

type Props = {
  defaultQ?: string
  defaultCategoria?: string
  defaultLetra?: string
  letrasDisponiveis: string[]
}

const CATS = {
  legislativo:   { label: 'Legislativo',   color: '#6366f1' }, // indigo
  eleitoral:     { label: 'Eleitoral',     color: '#10b981' }, // emerald
  financeiro:    { label: 'Financeiro',    color: '#f59e0b' }, // amber
  institucional: { label: 'Institucional', color: '#f43f5e' }, // rose
} as const

const TODAS_LETRAS = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ'.split('')

export function GlossarioFiltros({
  defaultQ = '',
  defaultCategoria = '',
  defaultLetra = '',
  letrasDisponiveis,
}: Props) {
  const router       = useRouter()
  const pathname     = usePathname()
  const searchParams = useSearchParams()
  const [isPending, startTransition] = useTransition()

  const [q, setQ] = useState(defaultQ)

  useEffect(() => {
    const syncQuery = window.setTimeout(() => setQ(defaultQ), 0)
    return () => window.clearTimeout(syncQuery)
  }, [defaultQ])

  function navegar(novoQ: string, novaCat: string, novaLetra: string) {
    const params = new URLSearchParams(searchParams.toString())

    if (novoQ.trim()) params.set('q', novoQ.trim()); else params.delete('q')
    if (novaCat)      params.set('categoria', novaCat); else params.delete('categoria')
    if (novaLetra)    params.set('letra', novaLetra); else params.delete('letra')

    const qs = params.toString()
    startTransition(() => router.push(qs ? `${pathname}?${qs}` : pathname))
  }

  // Debounced search
  useEffect(() => {
    const currentQ = searchParams.get('q') || ''
    if (q === currentQ) return

    const timer = setTimeout(() => {
      navegar(q, defaultCategoria, defaultLetra)
    }, 300)

    return () => clearTimeout(timer)
  }, [q])

  function clearAll() {
    setQ('')
    startTransition(() => router.push(pathname))
  }

  const hasActiveFilters = defaultQ || defaultCategoria || defaultLetra

  return (
    <div className="flex flex-col gap-6 mb-8">
      {/* Estilos específicos locais baseados em utilitários CSS */}
      <style dangerouslySetInnerHTML={{ __html: `
        .glossario-input-container {
          transition: border-color 0.15s ease, box-shadow 0.15s ease;
        }
        .glossario-input-container:focus-within {
          border-color: #6366f1 !important;
          box-shadow: 0 0 0 3px rgba(99, 102, 241, 0.2) !important;
        }
        .glossario-nav-scroll::-webkit-scrollbar {
          display: none;
        }
        .glossario-nav-scroll {
          scrollbar-width: none;
        }
      ` }} />

      {/* Linha da Busca + Botão de Limpar */}
      <div className="flex flex-wrap gap-4 items-center justify-between">
        <form onSubmit={(e) => { e.preventDefault(); navegar(q, defaultCategoria, defaultLetra) }} className="relative w-full max-w-md">
          <div className="glossario-input-container flex items-center bg-slate-900 border border-slate-800 rounded-xl h-11 overflow-hidden shadow-inner">
            <span className="pl-4 pr-2 text-slate-500 flex items-center">
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
                <circle cx="11" cy="11" r="8"/><path d="m21 21-4.35-4.35"/>
              </svg>
            </span>
            <input
              type="text"
              value={q}
              onChange={(e) => setQ(e.target.value)}
              placeholder="Buscar termo no glossário..."
              className="flex-1 bg-transparent border-0 outline-none h-full text-sm text-slate-200 placeholder-slate-500 font-sans"
            />
            {q && (
              <button
                type="button"
                onClick={() => setQ('')}
                className="px-3 h-full bg-transparent border-0 text-slate-500 hover:text-slate-200 transition-colors cursor-pointer"
                aria-label="Limpar termo"
              >
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                  <path d="M18 6 6 18M6 6l12 12"/>
                </svg>
              </button>
            )}
          </div>
        </form>

        {hasActiveFilters && (
          <button
            onClick={clearAll}
            className="text-xs font-mono font-bold text-indigo-400 hover:text-indigo-300 uppercase tracking-wider bg-indigo-500/10 hover:bg-indigo-500/20 px-3 py-1.5 rounded-lg border border-indigo-500/20 transition-all duration-200"
          >
            Limpar Filtros
          </button>
        )}
      </div>

      {/* Navegação A-Z */}
      <div className="glossario-nav-scroll flex items-center gap-1 bg-slate-950 border border-slate-900 rounded-xl p-1.5 overflow-x-auto select-none">
        <button
          onClick={() => navegar(q, defaultCategoria, '')}
          className={`flex items-center justify-center min-w-[48px] h-9 rounded-lg font-mono text-[11px] font-bold transition-all duration-200 cursor-pointer ${
            !defaultLetra
              ? 'bg-indigo-600 text-white shadow-md'
              : 'text-slate-400 hover:text-slate-200 hover:bg-slate-900/60'
          }`}
        >
          ALL
        </button>

        {TODAS_LETRAS.map((letra) => {
          const disponivel = letrasDisponiveis.includes(letra)
          const ativa = defaultLetra === letra

          return (
            <button
              key={letra}
              disabled={!disponivel && !ativa}
              onClick={() => navegar(q, defaultCategoria, letra)}
              className={`flex items-center justify-center min-w-[36px] h-9 rounded-lg font-mono text-xs font-bold transition-all duration-200 cursor-pointer ${
                ativa
                  ? 'bg-indigo-600 text-white shadow-md'
                  : disponivel
                  ? 'text-slate-300 hover:text-slate-100 hover:bg-slate-900/60'
                  : 'text-slate-700 cursor-not-allowed opacity-40'
              }`}
            >
              {letra}
            </button>
          )
        })}
      </div>

      {/* Categorias */}
      <div className="flex flex-wrap items-center gap-2.5">
        <span className="text-[10px] font-mono font-extrabold tracking-wider text-slate-500 uppercase mr-1.5">
          Categoria:
        </span>

        <button
          onClick={() => navegar(q, '', defaultLetra)}
          className={`px-3.5 py-1.5 rounded-full text-xs font-semibold border transition-all duration-200 cursor-pointer ${
            !defaultCategoria
              ? 'bg-slate-200 text-slate-950 border-slate-200 shadow-sm font-bold'
              : 'bg-slate-900 text-slate-300 border-slate-800 hover:border-slate-700'
          }`}
        >
          Todos
        </button>

        {Object.entries(CATS).map(([cat, { label, color }]) => {
          const ativa = defaultCategoria === cat
          return (
            <button
              key={cat}
              onClick={() => navegar(q, cat, defaultLetra)}
              className={`inline-flex items-center gap-2 px-3.5 py-1.5 rounded-full text-xs font-semibold border transition-all duration-200 cursor-pointer ${
                ativa
                  ? 'bg-indigo-600 text-white border-indigo-600 shadow-md font-bold'
                  : 'bg-slate-900 text-slate-300 border-slate-800 hover:border-slate-700'
              }`}
            >
              <span className="w-2 h-2 rounded-full flex-shrink-0" style={{ background: color }} />
              {label}
            </button>
          )
        })}

        {isPending && (
          <span className="text-xs text-slate-500 font-mono italic animate-pulse ml-2 flex items-center gap-1.5">
            <span className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-ping" />
            Buscando verbetes...
          </span>
        )}
      </div>
    </div>
  )
}

