          <div className="filter-segmented-control">
            {filtros.map((item) => (
              <button
                key={item}
                type="button"
                onClick={() => mudarFiltro(item)}
                className={`filter-pill ${item === filtro ? 'filter-pill-active' : ''}`}
              >
                {item}
              </button>
            ))}
          </div>
        )}
      </div>

      <div style={{ padding: '0 16px 16px', display: 'grid', gap: 14 }}>
        {loading ? (
