            </div>

            {sugestoes.length > 0 && (
              <div 
                style={{ 
                  display: 'grid', 
                  gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))', 
                  gap: 12, 
                  marginTop: 16,
                  textAlign: 'left',
