                { label: 'SIM',    bg: 'var(--pos-soft)', fg: 'var(--pos)' },
                { label: 'NÃO',   bg: 'var(--neg-soft)', fg: 'var(--neg)' },
                { label: 'ABS',   bg: 'var(--warn-soft)', fg: 'var(--warn)' },
