                    <div style={{ height: 10, background: 'var(--line)', borderRadius: 4, width: 64 }} />
                  </div>
                  {/* Proposition */}
                  <div className="flex flex-col gap-1 w-full">
                    <div style={{ height: 10, background: 'var(--line)', borderRadius: 4, width: '75%', marginBottom: 2 }} />
